Here is a clean reimplementation of what the obfuscated code does.

It builds a random grid with obstacles, then uses an A*-style search with 8-direction movement to find a route from the top-left corner to the bottom-right corner.

```javascript
const gridWidth = 20;
const gridHeight = 15;

const config = {
  heuristic: "manhattan",   // "manhattan" or "euclidean"
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  obstacleChance: 0.25
};

/**
 * Create a random grid:
 * 0 = walkable
 * 1 = blocked
 */
function createRandomGrid(width, height, obstacleChance) {
  const grid = [];

  for (let y = 0; y < height; y++) {
    grid[y] = [];
    for (let x = 0; x < width; x++) {
      grid[y][x] = Math.random() < obstacleChance ? 1 : 0;
    }
  }

  return grid;
}

const grid = createRandomGrid(gridWidth, gridHeight, config.obstacleChance);

const start = { x: 0, y: 0 };
const goal = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and goal are always walkable
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

function heuristicDistance(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (config.heuristic === "manhattan") {
    return dx + dy;
  }

  return Math.sqrt(dx * dx + dy * dy);
}

function pointKey(point) {
  return `${point.x},${point.y}`;
}

function parsePointKey(key) {
  const [x, y] = key.split(",").map(Number);
  return { x, y };
}

/**
 * Returns all valid walkable neighbors of a node.
 * Includes 8 directions.
 */
function getNeighbors(node, grid, width, height) {
  const directions = [
    { dx: 0, dy: -1, cost: config.straightCost },
    { dx: 0, dy: 1, cost: config.straightCost },
    { dx: -1, dy: 0, cost: config.straightCost },
    { dx: 1, dy: 0, cost: config.straightCost },
    { dx: -1, dy: -1, cost: config.diagonalCost },
    { dx: 1, dy: -1, cost: config.diagonalCost },
    { dx: -1, dy: 1, cost: config.diagonalCost },
    { dx: 1, dy: 1, cost: config.diagonalCost }
  ];

  const neighbors = [];

  for (const dir of directions) {
    const x = node.x + dir.dx;
    const y = node.y + dir.dy;

    const inBounds =
      x >= 0 &&
      x < width &&
      y >= 0 &&
      y < height;

    if (!inBounds) continue;
    if (grid[y][x] !== 0) continue;

    neighbors.push({
      x,
      y,
      moveCost: dir.cost
    });
  }

  return neighbors;
}

/**
 * A* pathfinding
 */
function findPath(start, goal, grid, width, height) {
  const openSet = {};
  const closedSet = {};
  const cameFrom = {};
  const gScore = {};
  const fScore = {};

  const startKey = pointKey(start);
  let iterations = 0;

  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = heuristicDistance(start, goal);

  while (
    Object.keys(openSet).length > 0 &&
    iterations < config.maxIterations
  ) {
    iterations++;

    // Find node in open set with lowest fScore
    let currentKey = null;
    let lowestF = Infinity;

    for (const key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    // Goal reached
    if (current.x === goal.x && current.y === goal.y) {
      const path = [current];
      let traceKey = currentKey;

      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        path.push(
          openSet[traceKey] ||
          closedSet[traceKey] ||
          parsePointKey(traceKey)
        );
      }

      return {
        path,
        cost: gScore[currentKey],
        iterations
      };
    }

    delete openSet[currentKey];
    closedSet[currentKey] = current;

    const neighbors = getNeighbors(current, grid, width, height);

    for (const neighbor of neighbors) {
      const neighborKey = pointKey(neighbor);

      if (closedSet[neighborKey]) {
        continue;
      }

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (
        gScore[neighborKey] === undefined ||
        tentativeG < gScore[neighborKey]
      ) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristicDistance(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return {
    path: [],
    cost: Infinity,
    iterations
  };
}

const result = findPath(start, goal, grid, gridWidth, gridHeight);

console.log(
  "Path length:",
  result.path.length,
  "Cost:",
  result.cost,
  "Iterations:",
  result.iterations
);
```

### What the original code is doing
In plain terms, the obfuscated code:

- creates a `20 x 15` grid
- randomly places obstacles with probability `0.25`
- forces the start `(0,0)` and goal `(19,14)` to be open
- supports 8-direction movement
- uses:
  - cost `1` for straight moves
  - cost `1.414` for diagonal moves
- uses a heuristic:
  - Manhattan by default
  - Euclidean if configured otherwise
- runs A* search
- returns:
  - `path`
  - `cost`
  - `iterations`

### One note
The original reconstructs the path from goal back to start and does **not reverse it**, so the returned path is in reverse order. The implementation above preserves that behavior.

